// Get the exe name. Free with `mwemu_free_string`.
char *mwemu_get_exe_name(struct MwemuEmu *emu);

// Set the exe name.
void mwemu_set_exe_name(struct MwemuEmu *emu, const char *value);

// Get the user name. Free with `mwemu_free_string`.
char *mwemu_get_user_name(struct MwemuEmu *emu);

