char *mwemu_get_temp_path(struct MwemuEmu *emu);

// Set the temp path.
void mwemu_set_temp_path(struct MwemuEmu *emu, const char *value);

// Get the current working directory path. Free with `mwemu_free_string`.
char *mwemu_get_cwd_path(struct MwemuEmu *emu);

// Set the current working directory path.
void mwemu_set_cwd_path(struct MwemuEmu *emu, const char *value);

// Get the Windows directory. Free with `mwemu_free_string`.
