// Set the host name.
void mwemu_set_host_name(struct MwemuEmu *emu, const char *value);

// Get the dump filename, or NULL if unset. Free with `mwemu_free_string`.
char *mwemu_get_dump_filename(struct MwemuEmu *emu);

// Set the dump filename; a NULL pointer clears it.
void mwemu_set_dump_filename(struct MwemuEmu *emu, const char *value);

// Get the trace filename, or NULL if unset. Free with `mwemu_free_string`.
char *mwemu_get_trace_filename(struct MwemuEmu *emu);

